+        assert!(result
+            .reasons
+            .contains(&"needs profiling data to increase confidence"));
+        assert!(result
+            .reasons
+            .contains(&"high potential impact justifies further investigation"));
+    }
+
+    #[test]
+    fn gate_result_reject_reasons() {
